issue_body:
Current ```__repr__``` has the following limitations:
- picks only protocol fields statically defined in ```__hdr__```;
- does not maintain order of these fields (it operates on a ```__hdr_defaults__``` that's a dict);
- some fields are just containers that are later broken into multiple fields using properties, these are displayed as-is;  it's more useful to display actual fields;
- does not display dynamically added fields.

Hi davisking.
## Expected Behavior
You said the speed of fast multiclass object detection is around 98FPS on your [blog](http://blog.dlib.net/2017/09/fast-multiclass-object-detection-in.html). But in my case, i can see only 13FPS with 928x478 resolutions. I want build dlib to faster.

## Current Behavior
I have a 6950X CPU and 1080ti GPU. So i think i built dlib wrong way.
I build dlib on windows batch with cudnn7.0 as below. 
```
cmake ../dlib^
 -G "Visual Studio 14 2015 Win64"^
 -T host=x64^
 -DCMAKE_BUILD_TYPE=RELEASE^
 -DCMAKE_INSTALL_PREFIX=build^
 -DCUDA_USE_STATIC_CUDA_RUNTIME=ON^
 -DDLIB_USE_CUDA=ON^
 -Dcudnn=..\cuda\lib\x64\cudnn.lib^
 -Dcudnn_include=..\cuda\include\^
cmake --build . --config Release --target ALL_BUILD
cmake --build . --config Release --target INSTALL
```


## Steps to Reproduce
And here is my detection sample.
```cpp
#include <iostream>
#include <chrono>
#define DLIB_USE_CUDA
#define DLIB_JPEG_SUPPORT
#include "dlib/dnn.h"
#include "dlib/image_io.h"
#include "dlib/gui_widgets.h"
#include "dlib/image_processing.h"
#include "dlib/opencv.h"
#include <opencv2/opencv.hpp>
#pragma comment(lib,"dlib_release_64bit_msvc1900.lib")
#pragma comment(lib,"cudart.lib")
#pragma comment(lib,"cublas.lib")
#pragma comment(lib,"cudnn.lib")
#pragma comment(lib,"cusolver.lib")
#pragma comment(lib,"curand.lib")
using namespace std;
using namespace dlib;

template <long num_filters, typename SUBNET> using con5d = con<num_filters, 5, 5, 2, 2, SUBNET>;
template <long num_filters, typename SUBNET> using con5 = con<num_filters, 5, 5, 1, 1, SUBNET>;
template <typename SUBNET> using downsampler = relu<affine<con5d<32, relu<affine<con5d<32, relu<affine<con5d<16, SUBNET>>>>>>>>>;
template <typename SUBNET> using rcon5 = relu<affine<con5<55, SUBNET>>>;
using net_type = loss_mmod<con<1, 9, 9, 1, 1, rcon5<rcon5<rcon5<downsampler<input_rgb_image_pyramid<pyramid_down<6>>>>>>>>;

int main()try {
	net_type net;
	shape_predictor sp;
	// You can get this file from http://dlib.net/files/mmod_front_and_rear_end_vehicle_detector.dat.bz2
	// This network was produced by the dnn_mmod_train_find_cars_ex.cpp example program.
	// As you can see, the file also includes a separately trained shape_predictor.  To see
	// a generic example of how to train those refer to train_shape_predictor_ex.cpp.
	deserialize("mmod_front_and_rear_end_vehicle_detector.dat") >> net >> sp;
	matrix<rgb_pixel> img;


	cv::VideoCapture vc;
	vc.open("drive.mp4");
	cv::Mat frame;
	while (vc.read(frame)) {
		cv::resize(frame, frame, cv::Size(928, 478));
		double start = clock();
		cv_image<bgr_pixel> cv_img(frame);
		assign_image(img, cv_img);
		auto network = net(img);
		for (auto&& d : network) {
			auto fd = sp(img, d);
			rectangle rect;
			for (unsigned long j = 0; j < fd.num_parts(); ++j)
				rect += fd.part(j);
			cv::Rect cvrect;
			cvrect.x = rect.left();
			cvrect.y = rect.top();
			cvrect.width = rect.width();
			cvrect.height = rect.height();
			//if (d.label == "rear")
				//cv::rectangle(frame, cvrect, cv::Scalar(0, 0, 255));
			//else
				//cv::rectangle(frame, cvrect, cv::Scalar(0, 255, 0));
		}
		//cv::imshow("frame", frame);
		//cv::waitKey(1);
		std::cout << 1 / ((clock() - start) / CLOCKS_PER_SEC) << std::endl;
	}

	cv::destroyAllWindows();
} catch (image_load_error& e) {
	cout << e.what() << endl; cout << "The test image is located in the examples folder.  So you should run this program from a sub folder so that the relative path is correct." << endl;
} catch (serialization_error& e) {
	cout << e.what() << endl; cout << "The correct model file can be obtained from: http://dlib.net/files/mmod_front_and_rear_end_vehicle_detector.dat.bz2" << endl;
} catch (std::exception& e) {
	cout << e.what() << endl;
}

```

